  1	import * as React from 'react';
  2	import { PREFIX } from '@odf/core/constants';
  3	import { getPrefix } from '@odf/core/utils';
  4	import { FieldLevelHelp, useCustomTranslation } from '@odf/shared';
  5	import { S3Commands } from '@odf/shared/s3';
  6	import UploadIcon from '@patternfly/react-icons/dist/esm/icons/upload-icon';
  7	import * as _ from 'lodash-es';
  8	import { observer } from 'mobx-react-lite';
  9	import { useDropzone } from 'react-dropzone';
 10	import { Trans } from 'react-i18next';
 11	import { useSearchParams } from 'react-router-dom-v5-compat';
 12	import { Icon, FlexItem, Flex, Title, Button } from '@patternfly/react-core';
 13	import { uploadStore } from '../store';
 14	import { UploadStatus } from '../types';
 15	import { UploadStatusBasedAlert } from '../upload-status/UploadStatusBasedAlert';
 16	import { convertFileToUploadProgress, uploadFile } from './uploads';
 17	import './fileUploadComponent.scss';
 18	
 19	type FileUploadComponentProps = {
 20	  s3Client: S3Commands;
 21	  bucketName: string;
 22	  showSidebar: () => void;
 23	  hideSidebar: () => void;
 24	  setCompletionTime: React.Dispatch<React.SetStateAction<number>>;
 25	  triggerRefresh: () => void;
 26	};
 27	
 28	export const FileUploadComponent: React.FC<FileUploadComponentProps> = observer(
 29	  ({
 30	    s3Client,
 31	    bucketName,
 32	    showSidebar,
 33	    hideSidebar,
 34	    setCompletionTime,
 35	    triggerRefresh,
 36	  }) => {
 37	    const { t } = useCustomTranslation();
 38	    const [uploadStatus, setUploadStatus] = React.useState<
 39	      | UploadStatus.INIT_STATE
 40	      | UploadStatus.UPLOAD_COMPLETE
 41	      | UploadStatus.UPLOAD_START
 42	    >(UploadStatus.INIT_STATE);
 43	
 44	    const [searchParams] = useSearchParams();
 45	    const foldersPath = searchParams.get(PREFIX) || '';
 46	
 47	    const processFiles = React.useCallback(
 48	      async (uploadObjects: File[]): Promise<number> => {
 49	        try {
 50	          const completionTime = await uploadFile(
 51	            uploadObjects,
 52	            s3Client,
 53	            bucketName,
 54	            foldersPath,
 55	            uploadStore
 56	          );
 57	          return completionTime;
 58	        } catch (e) {
 59	          // eslint-disable-next-line no-console
 60	          console.error('Error uploading file', e);
 61	        }
 62	      },
 63	      [bucketName, s3Client, foldersPath]
 64	    );
 65	
 66	    const closeAlert = React.useCallback(() => {
 67	      setUploadStatus(UploadStatus.INIT_STATE);
 68	      hideSidebar();
 69	      uploadStore.clearAll();
 70	    }, [hideSidebar]);
 71	
 72	    const onDrop = React.useCallback(
 73	      async (acceptedFiles: File[]) => {
 74	        closeAlert();
 75	        acceptedFiles.forEach((file) => {
 76	          const key = getPrefix(
 77	            file.webkitRelativePath || file.name,
 78	            foldersPath
 79	          );
 80	          uploadStore.addFile(convertFileToUploadProgress(file, key), key);
 81	        });
 82	        if (!!acceptedFiles.length) {
 83	          setUploadStatus(UploadStatus.UPLOAD_START);
 84	          const batches = _.chunk(acceptedFiles, 6);
 85	          let completionTime: number;
 86	          for (const batch of batches) {
 87	            // eslint-disable-next-line no-await-in-loop
 88	            completionTime = await processFiles(batch);
 89	          }
 90	          setCompletionTime(completionTime);
 91	        }
 92	        setUploadStatus(UploadStatus.UPLOAD_COMPLETE);
 93	        triggerRefresh();
 94	      },
 95	      [closeAlert, foldersPath, processFiles, setCompletionTime, triggerRefresh]
 96	    );
 97	
 98	    const { getRootProps, getInputProps } = useDropzone({
 99	      onDrop,
100	      useFsAccessApi: false,
101	    });
102	
103	    const abortAll = () => {
104	      setUploadStatus(UploadStatus.UPLOAD_COMPLETE);
105	    };
106	
107	    return (
108	      <div className="odf-upload">
109	        {(uploadStatus === UploadStatus.UPLOAD_START ||
110	          uploadStatus === UploadStatus.UPLOAD_COMPLETE) && (
111	          <UploadStatusBasedAlert
112	            showSidebar={showSidebar}
113	            closeAlert={closeAlert}
114	            abortAll={abortAll}
115	          />
116	        )}
117	        <Title headingLevel="h4">
118	          {t('Add objects')}
119	          <FieldLevelHelp>
120	            <Trans t={t}>
121	              Transfer files to cloud storage, where each file (object) is
122	              stored with a unique identifier and metadata. By default, objects
123	              are private. To configure permissions or properties for objects in
124	              an S3 bucket, users can use the Command Line Interface (CLI),
125	              Management Console, or SDKs. To make objects publicly accessible
126	              or apply more specific permissions, users can set bucket policies,
127	              use access control lists (ACLs), or define roles based on their
128	              requirements.
129	            </Trans>
130	          </FieldLevelHelp>
131	        </Title>
132	        <div {...getRootProps()}>
133	          <input {...getInputProps({ webkitdirectory: 'true' } as any)} />
134	          <Flex className="odf-upload__title">
135	            <FlexItem className="odf-upload-title__button">
136	              <Flex>
137	                <FlexItem>
138	                  <Flex>
139	                    <FlexItem>
140	                      <Icon status="info">
141	                        <UploadIcon />
142	                      </Icon>
143	                    </FlexItem>
144	                    <FlexItem>
145	                      <Title headingLevel="h5">
146	                        {t('Drag and drop files/folders here.')}
147	                      </Title>
148	                    </FlexItem>
149	                  </Flex>
150	                </FlexItem>
151	                <FlexItem>
152	                  <FlexItem className="odf-upload__helper-text">
153	                    <Trans t={t}>
154	                      For objects, multipart upload will upload the object in
155	                      parts, which are assembled in the bucket.
156	                    </Trans>
157	                  </FlexItem>
158	                </FlexItem>
159	              </Flex>
160	            </FlexItem>
161	            <FlexItem className="odf-upload-title__input">
162	              <Button variant="secondary">{t('Upload')}</Button>
163	            </FlexItem>
164	          </Flex>
165	        </div>
166	      </div>
167	    );
168	  }
169	);

